import React, { useEffect, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { createArtiste, getArtiste, updateArtiste } from '../api/artisteService';

export default function ArtisteForm(){
  const { id } = useParams();
  const navigate = useNavigate();
  const [model, setModel] = useState({ nom: '', description: '' });
  const [loading, setLoading] = useState(false);

  useEffect(()=>{
    if(id){
      setLoading(true);
      getArtiste(id).then(r=>setModel(r.data || {})).finally(()=>setLoading(false));
    }
  },[id]);

  const submit = (e) => {
    e.preventDefault();
    setLoading(true);
    const op = id ? updateArtiste(id, model) : createArtiste(model);
    op.then(()=>navigate('/artistes')).finally(()=>setLoading(false));
  };

  return (
    <div>
      <h1>{id ? 'Modifier' : 'Créer'} Artiste</h1>
      <form onSubmit={submit}>
        <div>
          <label>Nom</label><br />
          <input value={model.nom || ''} onChange={e=>setModel({...model, nom:e.target.value})} />
        </div>
        <div style={{marginTop:8}}>
          <label>Description</label><br />
          <textarea value={model.description || ''} onChange={e=>setModel({...model, description:e.target.value})} />
        </div>
        <div style={{marginTop:12}}>
          <button type="submit" disabled={loading}>{loading ? 'En cours...' : 'Enregistrer'}</button>
        </div>
      </form>
    </div>
  );
}
